import sys

# Definition for a binary tree node.
class TreeNode:
    def __init__(self, val=0, left=None, right=None):
        self.val = val
        self.left = left
        self.right = right
class Solution:
    def insertIntoBST(self, root: TreeNode, val: int) -> TreeNode:
        if not root:
            return TreeNode(val)
        node = root
        while node:
            if val > node.val:
                if not node.right:
                    node.right = TreeNode(val)
                    return root
                node = node.right
            else:
                if not node.left:
                    node.left = TreeNode(val)
                    return root
                node = node.left

def print_tree(node):
    if node:
        print_tree(node.left)
        print(node.val)
        print_tree(node.right)

if __name__ == '__main__':
    it = iter(sys.stdin.read().split())
    try:
        n = int(next(it))
        root = None
        for _ in range(n):
            val = int(next(it))
            if not root:
                root = TreeNode(val)
            else:
                node = root
                while node:
                    if val > node.val:
                        if not node.right:
                            node.right = TreeNode(val)
                            break
                        node = node.right
                    else:
                        if not node.left:
                            node.left = TreeNode(val)
                            break
                        node = node.left
        insert_val = int(next(it))
        sol = Solution()
        root = sol.insertIntoBST(root, insert_val)
        nodes = []
