#include <numeric>
#include <iostream>
#include <vector>
using namespace std;

// Definition for a binary tree node.
struct TreeNode {
    int val;
    TreeNode *left;
    TreeNode *right;
    TreeNode() : val(0), left(nullptr), right(nullptr) {}
    TreeNode(int x) : val(x), left(nullptr), right(nullptr) {}
    TreeNode(int x, TreeNode *left, TreeNode *right) : val(x), left(left), right(right) {}
};

class Solution {
public:
    TreeNode* insertIntoBST(TreeNode* root, int val) {
        if (!root) {
            return new TreeNode(val);
        }
        TreeNode* node = root;
        while (node) {
            if (val > node->val) {
                if (!node->right) {
                    node->right = new TreeNode(val);
                    return root;
                }
                node = node->right;
            } else {
                if (!node->left) {
                    node->left = new TreeNode(val);
                    return root;
                }
                node = node->left;
            }
        }
    }
};

void inorder_traversal(TreeNode* node, vector<int>& nodes) {
    if (node) {
        inorder_traversal(node->left, nodes);
        nodes.push_back(node->val);
        inorder_traversal(node->right, nodes);
    }
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    cin >> n;
    TreeNode* root = nullptr;
    for (int i = 0; i < n; i++) {
        int val;
        cin >> val;
        if (!root) {
            root = new TreeNode(val);
        } else {
            TreeNode* node = root;
            while (node) {
                if (val > node->val) {
                    if (!node->right) {
                        node->right = new TreeNode(val);
                        break;
                    }
                    node = node->right;
                } else {
                    if (!node->left) {
                        node->left = new TreeNode(val);
                        break;
                    }
                    node = node->left;
                }
            }
        }
    }
    int insert_val;
    cin >> insert_val;
    Solution sol;
    root = sol.insertIntoBST(root, insert_val);
    vector<int> nodes;
    inorder_traversal(root, nodes);
    cout << nodes.size() << endl;
    for (int node : nodes) {
        cout << node << endl;
    }
    return 0;
}
